#include <iostream>

using namespace std;

int main()
{
    int age = 20;

    if (age >= 18)
    {
        cout << "You are an adult.";
    }

    return 0;
}

if (age >= 18)
    cout << "You are an adult.";
    cout << "This always runs, regardless of age!"; // NOT inside the if

int a = 3;

if (a = 5) // assignment, not comparison!
{
    cout << "This always runs";
}

bool isLoggedIn = true;

if (isLoggedIn)
{
    cout << "Welcome back!";
}

int age = 20;
bool hasID = true;

if (age >= 18)
{
    if (hasID)
    {
        cout << "Entry allowed.";
    }
}

